using System;
using System.Collections.Generic;
using System.Drawing;
using System.Net.WebSockets;
using System.Text;
using System.Threading;
using System.Threading.Tasks;
using System.Web.Script.Serialization;
using GTA;
using GTA.Math;
using GTA.Native;

namespace ModProject
{
    public class Mod : Script
    {
        // ==================== 游戏状态 ====================
        private enum GameState
        {
            Idle,
            Active,
            Completed,
            Failed
        }

        private GameState _state = GameState.Idle;
        private Vehicle _missionVehicle;
        private Vector3 _destination;
        private Vector3 _detourCheckpoint;
        private bool _hasDetour;
        private DateTime _gameStartTime;
        private DateTime _lastVehicleCheckTime;
        private const double GameDurationMinutes = 10.0;
        private const double MaxOutOfVehicleSeconds = 30.0;
        private DateTime _outOfVehicleSince = DateTime.MaxValue;

        // ==================== 效果冷却 ====================
        private Dictionary<string, DateTime> _cooldowns = new Dictionary<string, DateTime>();
        private const double CooldownSeconds = 15.0;

        // ==================== 活跃效果计时器 ====================
        private Dictionary<string, DateTime> _activeEffects = new Dictionary<string, DateTime>();

        // ==================== 生成的NPC/车辆追踪 ====================
        private List<Ped> _chasers = new List<Ped>();
        private List<Vehicle> _chaserVehicles = new List<Vehicle>();
        private List<Ped> _escorts = new List<Ped>();
        private List<Vehicle> _escortVehicles = new List<Vehicle>();

        // ==================== LIVE Studio ====================
        private ClientWebSocket _webSocket;
        private CancellationTokenSource _cts;
        private Queue<Action> _mainThreadActions = new Queue<Action>();
        private readonly object _actionLock = new object();
        private const string LiveStudioUrl = "ws://127.0.0.1:60080";

        // ==================== 终点标记 ====================
        private Vector3 _destinationMarkerPos;
        private Vector3 _detourMarkerPos;

        public Mod()
        {
            Tick += OnTick;
            Interval = 100; // 100ms

            // 初始化状态
            _state = GameState.Idle;
            _hasDetour = false;

            // 启动 WebSocket 连接
            Task.Run(() => ConnectWebSocketAsync());
        }

        // ==================== 主Tick ====================
        private void OnTick(object sender, EventArgs e)
        {
            // 处理主线程队列
            ProcessMainThreadActions();

            switch (_state)
            {
                case GameState.Idle:
                    HandleIdleState();
                    break;
                case GameState.Active:
                    HandleActiveState();
                    break;
                case GameState.Completed:
                    HandleCompletedState();
                    break;
                case GameState.Failed:
                    HandleFailedState();
                    break;
            }
        }

        private void ProcessMainThreadActions()
        {
            lock (_actionLock)
            {
                while (_mainThreadActions.Count > 0)
                {
                    var action = _mainThreadActions.Dequeue();
                    try
                    {
                        action();
                    }
                    catch (Exception ex)
                    {
                        // 静默处理异常
                    }
                }
            }
        }

        private void EnqueueMainThreadAction(Action action)
        {
            lock (_actionLock)
            {
                if (_mainThreadActions.Count < 100)
                {
                    _mainThreadActions.Enqueue(action);
                }
            }
        }

        // ==================== 状态处理 ====================
        private void HandleIdleState()
        {
            // 显示提示：使用 !start 开始
            if (Game.Player.Character.IsInVehicle())
            {
                // 可以开始
            }
        }

        private void HandleActiveState()
        {
            var player = Game.Player.Character;

            // 检查超时
            if ((DateTime.UtcNow - _gameStartTime).TotalMinutes >= GameDurationMinutes)
            {
                FailGame("⏰ 时间耗尽！货物未能送达。");
                return;
            }

            // 检查任务车辆是否存在且未被摧毁
            if (_missionVehicle == null || !_missionVehicle.Exists() || _missionVehicle.IsDead)
            {
                FailGame("💥 任务车辆被摧毁！货物丢失。");
                return;
            }

            // 检查玩家是否在任务车辆中
            if (player.CurrentVehicle != _missionVehicle)
            {
                // 玩家在另一辆车中 → 失败
                if (player.IsInVehicle() && player.CurrentVehicle != null && player.CurrentVehicle != _missionVehicle)
                {
                    FailGame("🚗 主播换车！任务失败。");
                    return;
                }

                // 玩家不在任何车中
                if (!player.IsInVehicle())
                {
                    if (_outOfVehicleSince == DateTime.MaxValue)
                    {
                        _outOfVehicleSince = DateTime.UtcNow;
                    }
                    else if ((DateTime.UtcNow - _outOfVehicleSince).TotalSeconds >= MaxOutOfVehicleSeconds)
                    {
                        FailGame("🚶 主播离开车辆太久！任务失败。");
                        return;
                    }
                }
            }
            else
            {
                _outOfVehicleSince = DateTime.MaxValue;
            }

            // 检查是否到达终点（或绕路检查点）
            if (_hasDetour && _detourCheckpoint != Vector3.Zero)
            {
                float distToDetour = (_missionVehicle.Position - _detourCheckpoint).Length();
                if (distToDetour < 15.0f)
                {
                    // 到达绕路检查点
                    _hasDetour = false;
                    _detourCheckpoint = Vector3.Zero;
                    UI.Notify("✅ 绕路检查点已到达！继续前往终点。");
                }
            }

            if (!_hasDetour)
            {
                float distToDest = (_missionVehicle.Position - _destination).Length();
                if (distToDest < 15.0f)
                {
                    CompleteGame();
                    return;
                }
            }

            // 更新效果过期检查
            CheckEffectExpirations(_missionVehicle);

            // 更新追兵行为
            UpdateChasers();

            // 更新护航行为
            UpdateEscorts();

            // 绘制终点标记
            DrawDestinationMarkers();

            // 显示剩余时间和距离
            if (DateTime.UtcNow.Second % 5 == 0 && _lastVehicleCheckTime.AddSeconds(1) < DateTime.UtcNow)
            {
                _lastVehicleCheckTime = DateTime.UtcNow;
                float remainingDist = (_missionVehicle.Position - _destination).Length();
                double remainingTime = GameDurationMinutes - (DateTime.UtcNow - _gameStartTime).TotalMinutes;
                string msg = string.Format("📦 货物运送中 | 剩余: {0:F1}分钟 | 距离: {1:F0}m",
                    Math.Max(0, remainingTime), remainingDist);
                if (_hasDetour)
                    msg += " | ⚠️ 请先前往绕路检查点";
                UI.ShowSubtitle(msg, 2000);
            }
        }

        private void HandleCompletedState()
        {
            // 游戏完成
            if (DateTime.UtcNow.Second % 3 == 0)
            {
                UI.Notify("🎉 货物已成功送达！");
            }
        }

        private void HandleFailedState()
        {
            // 游戏失败
        }

        // ==================== 游戏流程 ====================
        private void StartGame()
        {
            var player = Game.Player.Character;
            if (!player.IsInVehicle())
            {
                UI.Notify("⚠️ 请先进入一辆车再使用 !start");
                return;
            }

            _missionVehicle = player.CurrentVehicle;
            if (_missionVehicle == null)
            {
                UI.Notify("⚠️ 无法识别当前车辆");
                return;
            }

            // 设置终点：玩家前方约 2000 米处
            Vector3 forward = _missionVehicle.ForwardVector;
            _destination = _missionVehicle.Position + forward * 2000f;
            // 确保终点在地面以上
            _destination.Z = World.GetGroundHeight(_destination) + 2f;

            _hasDetour = false;
            _detourCheckpoint = Vector3.Zero;
            _gameStartTime = DateTime.UtcNow;
            _outOfVehicleSince = DateTime.MaxValue;
            _state = GameState.Active;

            // 清理旧的 NPC
            CleanupAllNPCs();

            // 标记车辆
            _missionVehicle.MarkAsNoLongerNeeded();

            UI.Notify("🚚 易碎货物送达任务开始！你有10分钟时间。");
            UI.Notify("💬 观众可使用聊天命令互动：!repair !shield !clear !boost !escort !puncture !stall !chase !grip !boom !detour");
        }

        private void CompleteGame()
        {
            _state = GameState.Completed;
            CleanupAllNPCs();
            UI.Notify("🎉 恭喜！货物已成功送达！");
            UI.Notify("🏆 任务完成！感谢观众参与。");
        }

        private void FailGame(string reason)
        {
            _state = GameState.Failed;
            CleanupAllNPCs();
            UI.Notify("❌ " + reason);
            UI.Notify("使用 !start 重新开始任务。");
        }

        // ==================== 观众互动效果 ====================
        private bool IsOnCooldown(string effectName)
        {
            if (_cooldowns.TryGetValue(effectName, out DateTime cooldownEnd))
            {
                if (DateTime.UtcNow < cooldownEnd)
                    return true;
            }
            return false;
        }

        private void SetCooldown(string effectName)
        {
            _cooldowns[effectName] = DateTime.UtcNow.AddSeconds(CooldownSeconds);
        }

        private void CheckEffectExpirations(Vehicle vehicle)
        {
            var now = DateTime.UtcNow;
            var expiredKeys = new List<string>();

            foreach (var kvp in _activeEffects)
            {
                if (now >= kvp.Value)
                {
                    expiredKeys.Add(kvp.Key);
                }
            }

            foreach (var key in expiredKeys)
            {
                _activeEffects.Remove(key);
                switch (key)
                {
                    case "shield_tires":
                        if (vehicle != null && vehicle.Exists())
                            vehicle.CanTiresBurst = true;
                        break;
                    case "boost":
                        if (vehicle != null && vehicle.Exists())
                            vehicle.EnginePowerMultiplier = 1.0f;
                        break;
                    case "stall":
                        if (vehicle != null && vehicle.Exists())
                            vehicle.IsEngineRunning = true;
                        break;
                    case "grip_down":
                        if (vehicle != null && vehicle.Exists())
                            vehicle.EnginePowerMultiplier = 1.0f;
                        break;
                }
            }
        }

        // ---- 正面效果 ----
        private void DoRepair()
        {
            if (_state != GameState.Active || _missionVehicle == null || !_missionVehicle.Exists())
                return;
            if (IsOnCooldown("repair")) return;

            // 修复25%
            int maxHealth = _missionVehicle.MaxHealth;
            int currentHealth = _missionVehicle.Health;
            int healAmount = (int)(maxHealth * 0.25f);
            int newHealth = Math.Min(maxHealth, currentHealth + healAmount);
            _missionVehicle.Health = newHealth;
            _missionVehicle.BodyHealth = Math.Min(_missionVehicle.BodyHealth + 250f, 1000f);
            _missionVehicle.EngineHealth = Math.Min(_missionVehicle.EngineHealth + 250f, 1000f);
            _missionVehicle.DirtLevel = 0f;

            SetCooldown("repair");
            UI.Notify("🔧 车辆修复25%！");
        }

        private void DoShieldTires()
        {
            if (_state != GameState.Active || _missionVehicle == null || !_missionVehicle.Exists())
                return;
            if (IsOnCooldown("shield")) return;

            _missionVehicle.CanTiresBurst = false;
            _activeEffects["shield_tires"] = DateTime.UtcNow.AddSeconds(30.0);

            SetCooldown("shield");
            UI.Notify("🛡️ 防爆轮胎激活！持续30秒。");
        }

        private void DoClearChasers()
        {
            if (_state != GameState.Active) return;
            if (IsOnCooldown("clear")) return;

            CleanupChasers();

            SetCooldown("clear");
            UI.Notify("🧹 追兵已被清空！");
        }

        private void DoBoost()
        {
            if (_state != GameState.Active || _missionVehicle == null || !_missionVehicle.Exists())
                return;
            if (IsOnCooldown("boost")) return;

            _missionVehicle.EnginePowerMultiplier = 2.5f;
            _activeEffects["boost"] = DateTime.UtcNow.AddSeconds(5.0);

            SetCooldown("boost");
            UI.Notify("🚀 加速5秒！");
        }

        private void DoEscort()
        {
            if (_state != GameState.Active || _missionVehicle == null || !_missionVehicle.Exists())
                return;
            if (IsOnCooldown("escort")) return;
            if (_escorts.Count >= 4) return; // 最多4个护航

            try
            {
                Vector3 spawnPos = _missionVehicle.Position + _missionVehicle.RightVector * 8f;
                spawnPos.Z = _missionVehicle.Position.Z;

                var escortVeh = World.CreateVehicle(new Model("fbi"), spawnPos, _missionVehicle.Heading);
                if (escortVeh == null) return;
                escortVeh.MarkAsNoLongerNeeded();

                var escortPed = escortVeh.CreatePedOnSeat(VehicleSeat.Driver, new Model("s_m_y_swat_01"));
                if (escortPed == null)
                {
                    escortVeh.Delete();
                    return;
                }
                escortPed.MarkAsNoLongerNeeded();
                escortPed.DrivingStyle = DrivingStyle.Normal;
                escortPed.DrivingSpeed = 30f;

                _escortVehicles.Add(escortVeh);
                _escorts.Add(escortPed);

                SetCooldown("escort");
                UI.Notify("🛡️ 护航NPC已派出！");
            }
            catch
            {
                // 忽略生成失败
            }
        }

        // ---- 负面效果 ----
        private void DoPuncture()
        {
            if (_state != GameState.Active || _missionVehicle == null || !_missionVehicle.Exists())
                return;
            if (IsOnCooldown("puncture")) return;

            // 模拟爆胎：允许爆胎 + 突然降速
            _missionVehicle.CanTiresBurst = true;
            Vector3 vel = _missionVehicle.Velocity;
            _missionVehicle.Velocity = vel * 0.5f;
            _missionVehicle.EnginePowerMultiplier = 0.6f;
            _activeEffects["grip_down"] = DateTime.UtcNow.AddSeconds(8.0);

            SetCooldown("puncture");
            UI.Notify("💥 爆胎！车辆失控。");
        }

        private void DoStall()
        {
            if (_state != GameState.Active || _missionVehicle == null || !_missionVehicle.Exists())
                return;
            if (IsOnCooldown("stall")) return;

            _missionVehicle.IsEngineRunning = false;
            _activeEffects["stall"] = DateTime.UtcNow.AddSeconds(4.0);

            SetCooldown("stall");
            UI.Notify("🔌 引擎熄火！");
        }

        private void DoChase()
        {
            if (_state != GameState.Active || _missionVehicle == null || !_missionVehicle.Exists())
                return;
            if (IsOnCooldown("chase")) return;
            if (_chasers.Count >= 6) return; // 最多6个追兵

            try
            {
                Vector3 spawnPos = _missionVehicle.Position - _missionVehicle.ForwardVector * 50f;
                spawnPos += _missionVehicle.RightVector * 15f;
                spawnPos.Z = _missionVehicle.Position.Z;

                var chaseVeh = World.CreateVehicle(new Model("police2"), spawnPos, _missionVehicle.Heading);
                if (chaseVeh == null) return;
                chaseVeh.MarkAsNoLongerNeeded();

                var chasePed = chaseVeh.CreatePedOnSeat(VehicleSeat.Driver, new Model("s_m_y_cop_01"));
                if (chasePed == null)
                {
                    chaseVeh.Delete();
                    return;
                }
                chasePed.MarkAsNoLongerNeeded();
                chasePed.DrivingStyle = DrivingStyle.Rushed;
                chasePed.DrivingSpeed = 45f;
                chasePed.Task.VehicleChase(Game.Player.Character);

                _chaserVehicles.Add(chaseVeh);
                _chasers.Add(chasePed);

                SetCooldown("chase");
                UI.Notify("🚔 追击车辆已派出！");
            }
            catch
            {
                // 忽略生成失败
            }
        }

        private void DoGripDown()
        {
            if (_state != GameState.Active || _missionVehicle == null || !_missionVehicle.Exists())
                return;
            if (IsOnCooldown("grip")) return;

            // 降低抓地力：大幅降低引擎功率
            _missionVehicle.EnginePowerMultiplier = 0.4f;
            _activeEffects["grip_down"] = DateTime.UtcNow.AddSeconds(10.0);

            SetCooldown("grip");
            UI.Notify("🛢️ 路面变滑！抓地力降低。");
        }

        private void DoBoom()
        {
            if (_state != GameState.Active || _missionVehicle == null || !_missionVehicle.Exists())
                return;
            if (IsOnCooldown("boom")) return;

            // 记录血量
            int healthBefore = _missionVehicle.Health;
            int minHealth = (int)(_missionVehicle.MaxHealth * 0.15f);

            // 在车辆附近爆炸
            Vector3 boomPos = _missionVehicle.Position + _missionVehicle.RightVector * 6f;
            World.AddExplosion(boomPos, ExplosionType.BombStandard, 4f, 0.5f);

            // 保留最低血量
            if (_missionVehicle.Exists() && _missionVehicle.Health < minHealth)
            {
                _missionVehicle.Health = minHealth;
            }

            SetCooldown("boom");
            UI.Notify("💣 附近爆炸！车辆受损。");
        }

        private void DoDetour()
        {
            if (_state != GameState.Active || _missionVehicle == null || !_missionVehicle.Exists())
                return;
            if (IsOnCooldown("detour")) return;
            if (_hasDetour) return; // 已有一个绕路检查点

            Vector3 midPoint = (_missionVehicle.Position + _destination) * 0.5f;
            Vector3 offset = _missionVehicle.RightVector * 300f;
            // 随机向左或向右
            if (new Random().Next(2) == 0)
                offset = -offset;

            _detourCheckpoint = midPoint + offset;
            _detourCheckpoint.Z = World.GetGroundHeight(_detourCheckpoint) + 2f;
            _hasDetour = true;

            SetCooldown("detour");
            UI.Notify("🔄 路线变更！请前往绕路检查点。");
        }

        // ==================== NPC 管理 ====================
        private void UpdateChasers()
        {
            for (int i = _chasers.Count - 1; i >= 0; i--)
            {
                var ped = _chasers[i];
                var veh = _chaserVehicles[i];

                if (ped == null || !ped.Exists() || ped.IsDead ||
                    veh == null || !veh.Exists() || veh.IsDead)
                {
                    CleanupChaserAt(i);
                    continue;
                }

                // 如果追兵没有任务，重新分配追逐任务
                if (!ped.IsInVehicle())
                {
                    CleanupChaserAt(i);
                    continue;
                }

                // 如果追兵离玩家太远（超过500米），删除
                float dist = (ped.Position - Game.Player.Character.Position).Length();
                if (dist > 500f)
                {
                    CleanupChaserAt(i);
                }
            }
        }

        private void UpdateEscorts()
        {
            for (int i = _escorts.Count - 1; i >= 0; i--)
            {
                var ped = _escorts[i];
                var veh = _escortVehicles[i];

                if (ped == null || !ped.Exists() || ped.IsDead ||
                    veh == null || !veh.Exists() || veh.IsDead)
                {
                    CleanupEscortAt(i);
                    continue;
                }

                if (!ped.IsInVehicle())
                {
                    CleanupEscortAt(i);
                    continue;
                }

                // 护航：跟随玩家前方位置
                if (_missionVehicle != null && _missionVehicle.Exists())
                {
                    Vector3 followPos = _missionVehicle.Position + _missionVehicle.ForwardVector * 15f;
                    ped.DrivingSpeed = 28f;
                    ped.Task.DriveTo(veh, followPos, 10f, 25f, DrivingStyle.Normal);
                }
            }
        }

        private void CleanupChaserAt(int index)
        {
            if (index >= 0 && index < _chasers.Count)
            {
                var ped = _chasers[index];
                var veh = _chaserVehicles[index];
                try
                {
                    if (ped != null && ped.Exists()) ped.Delete();
                    if (veh != null && veh.Exists()) veh.Delete();
                }
                catch { }
                _chasers.RemoveAt(index);
                _chaserVehicles.RemoveAt(index);
            }
        }

        private void CleanupEscortAt(int index)
        {
            if (index >= 0 && index < _escorts.Count)
            {
                var ped = _escorts[index];
                var veh = _escortVehicles[index];
                try
                {
                    if (ped != null && ped.Exists()) ped.Delete();
                    if (veh != null && veh.Exists()) veh.Delete();
                }
                catch { }
                _escorts.RemoveAt(index);
                _escortVehicles.RemoveAt(index);
            }
        }

        private void CleanupChasers()
        {
            for (int i = _chasers.Count - 1; i >= 0; i--)
            {
                CleanupChaserAt(i);
            }
        }

        private void CleanupAllNPCs()
        {
            CleanupChasers();
            for (int i = _escorts.Count - 1; i >= 0; i--)
            {
                CleanupEscortAt(i);
            }
        }

        // ==================== 绘制标记 ====================
        private void DrawDestinationMarkers()
        {
            if (_state != GameState.Active) return;

            // 绘制终点
            if (!_hasDetour)
            {
                World.DrawMarker(MarkerType.CheckeredFlagRect,
                    _destination + new Vector3(0, 0, 1.5f),
                    Vector3.Zero, Vector3.Zero,
                    new Vector3(2f, 2f, 2f),
                    Color.Yellow, false, false, false, null, null, false);
            }

            // 绘制绕路检查点
            if (_hasDetour && _detourCheckpoint != Vector3.Zero)
            {
                World.DrawMarker(MarkerType.VerticalCylinder,
                    _detourCheckpoint + new Vector3(0, 0, 1.5f),
                    Vector3.Zero, Vector3.Zero,
                    new Vector3(2f, 2f, 2f),
                    Color.Orange, false, false, false, null, null, false);
            }
        }

        // ==================== WebSocket ====================
        private async Task ConnectWebSocketAsync()
        {
            while (true)
            {
                try
                {
                    using (_cts = new CancellationTokenSource())
                    using (_webSocket = new ClientWebSocket())
                    {
                        await _webSocket.ConnectAsync(new Uri(LiveStudioUrl), _cts.Token);

                        // 订阅消息
                        var subMsg = "{\"type\":\"serviceSignalSub\",\"payload\":{\"signal\":\"IM_MESSAGE_TRANSPORT\"}}";
                        var subBytes = Encoding.UTF8.GetBytes(subMsg);
                        await _webSocket.SendAsync(new ArraySegment<byte>(subBytes),
                            WebSocketMessageType.Text, true, _cts.Token);

                        // 接收循环
                        var buffer = new byte[8192];
                        var messageBuilder = new StringBuilder();

                        while (_webSocket.State == WebSocketState.Open)
                        {
                            var result = await _webSocket.ReceiveAsync(
                                new ArraySegment<byte>(buffer), _cts.Token);

                            if (result.MessageType == WebSocketMessageType.Close)
                                break;

                            messageBuilder.Append(Encoding.UTF8.GetString(buffer, 0, result.Count));

                            if (result.EndOfMessage)
                            {
                                string fullMessage = messageBuilder.ToString();
                                messageBuilder.Clear();
                                ProcessLiveMessage(fullMessage);
                            }
                        }
                    }
                }
                catch (Exception)
                {
                    // 连接失败，等待后重试
                }

                await Task.Delay(5000); // 5秒后重连
            }
        }

        private void ProcessLiveMessage(string json)
        {
            try
            {
                var serializer = new JavaScriptSerializer();
                var msg = serializer.Deserialize<LiveMessage>(json);

                if (msg == null || msg.common == null) return;

                string method = msg.common.method;

                if (method == "WebcastChatMessage")
                {
                    string content = msg.content ?? string.Empty;
                    ProcessChatCommand(content);
                }
                // WebcastGiftMessage 在当前 DESIGN.md 中不需要处理
            }
            catch
            {
                // 解析失败，忽略
            }
        }

        private void ProcessChatCommand(string content)
        {
            if (string.IsNullOrWhiteSpace(content)) return;
            content = content.Trim().ToLowerInvariant();

            Action action = null;

            switch (content)
            {
                case "!start":
                    action = () => { if (_state == GameState.Idle || _state == GameState.Failed || _state == GameState.Completed) StartGame(); };
                    break;
                case "!repair":
                    action = DoRepair;
                    break;
                case "!shield":
                    action = DoShieldTires;
                    break;
                case "!clear":
                    action = DoClearChasers;
                    break;
                case "!boost":
                    action = DoBoost;
                    break;
                case "!escort":
                    action = DoEscort;
                    break;
                case "!puncture":
                    action = DoPuncture;
                    break;
                case "!stall":
                    action = DoStall;
                    break;
                case "!chase":
                    action = DoChase;
                    break;
                case "!grip":
                    action = DoGripDown;
                    break;
                case "!boom":
                    action = DoBoom;
                    break;
                case "!detour":
                    action = DoDetour;
                    break;
            }

            if (action != null)
            {
                EnqueueMainThreadAction(action);
            }
        }

        // ==================== 清理 ====================
        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                try
                {
                    _cts?.Cancel();
                    _webSocket?.Dispose();
                }
                catch { }
                CleanupAllNPCs();
            }
            base.Dispose(disposing);
        }

        // ==================== DTO ====================
        private class LiveMessage
        {
            public LiveCommon common { get; set; }
            public string content { get; set; }
        }

        private class LiveCommon
        {
            public string method { get; set; }
        }
    }
